/**
 * @name Path traversal via file construction from external input
 * @description Detects File or Path construction from potentially tainted input
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-file-construction
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // Method parameters from external input (YAML/config parsing)
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("get") and
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util", "Map")
        or
        mc.getMethod().hasName("getString") or
        mc.getMethod().hasName("getParameter")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get()
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Path.resolve()
    exists(MethodCall mc |
      mc.getMethod().hasName("resolve") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "Path") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FileInputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal: file path construction from $@.", source.getNode(), "external input"

/**
 * @name KubeConfig file path loading from untrusted YAML data
 * @description KubeConfig loads file paths from YAML map data and passes them to File/FileInputStream
 * @kind path-problem
 * @problem.severity error
 * @id java/kubeconfig-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// Model KubeConfig.getData() and similar map access as sources of external data
module KubeConfigPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Data read from YAML Map structures in KubeConfig
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util", "Map") and
      source.asExpr() = mc
    )
    or
    // String values coming from YAML parsing via SnakeYAML
    exists(MethodCall mc |
      mc.getMethod().hasName("load") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.yaml.snakeyaml", "Yaml") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get()
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // new BufferedReader(new FileReader(...))
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileReader") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module KubeConfigPathFlow = TaintTracking::Global<KubeConfigPathConfig>;
import KubeConfigPathFlow::PathGraph

from KubeConfigPathFlow::PathNode source, KubeConfigPathFlow::PathNode sink
where KubeConfigPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal: file path from YAML/Map data flows to $@.", source.getNode(), "YAML/Map data"

/**
 * @name ZipEntry name flowing to file construction (Zip Slip)
 * @description ZipEntry.getName() used in file construction without path validation
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // ZipEntry.getName() as source
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
    or
    // TarArchiveEntry.getName() as source
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.compress.archivers.tar", "TarArchiveEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileOutputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get()
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Path.resolve()
    exists(MethodCall mc |
      mc.getMethod().hasName("resolve") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "Path") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

